SELECT mid, cid, mtitle, mcontent, mpublish
FROM message
WHERE (mnum = -1 OR mid IN (
    SELECT mid FROM sm WHERE sid = (SELECT sid FROM student WHERE sphone = #{sphone}) AND isread = 0
)) AND cid = #{cid}
ORDER BY mpublish DESC

SELECT mid, cid, mtitle, mcontent, mpublish
FROM message WHERE mnum = -1 AND cid = #{cid}
ORDER BY mpublish DESC
